'use strict'

const parseArgs = require('./args')
const parseArgsLib = require('./lib/parse-args')
const log = require('./log')
const {
  exit,
  requireFastifyForModule,
  requireServerPluginFromPath,
  showHelpForCommand
} = require('./util')
const fp = require('fastify-plugin')
const { loadEnvQuitely } = require('./env-loader')

let Fastify = null

function loadModules (opts) {
  try {
    Fastify = requireFastifyForModule(opts._[0]).module
  } catch (e) {
    module.exports.stop(e)
  }
}

async function generateSwagger (args) {
  const opts = parseArgs(args)
  const extraOpts = parseArgsLib(args, {
    options: {
      yaml: { type: 'boolean' }
    }
  })
  if (opts.help) {
    return showHelpForCommand('generate-swagger')
  }

  if (opts._.length !== 1) {
    console.error('Missing the required file parameter\n')
    return showHelpForCommand('generate-swagger')
  }

  loadModules(opts)

  const fastify = await runFastify(opts)
  try {
    if (fastify.swagger == null) {
      log('error', '@fastify/swagger plugin not installed')
      process.exit(1)
    }

    if (extraOpts.yaml) {
      return fastify.swagger({ yaml: true })
    } else {
      return JSON.stringify(fastify.swagger(), undefined, 2)
    }
  } finally {
    fastify.close()
  }
}

async function runFastify (opts) {
  loadEnvQuitely()

  let file = null

  try {
    file = await requireServerPluginFromPath(opts._[0])
  } catch (e) {
    return module.exports.stop(e)
  }

  const fastify = Fastify(opts.options)

  const pluginOptions = {}
  if (opts.prefix) {
    pluginOptions.prefix = opts.prefix
  }

  await fastify.register(fp(file), pluginOptions)
  await fastify.ready()

  return fastify
}

function stop (message) {
  exit(message)
}

function cli (args) {
  return generateSwagger(args).then(swagger => {
    process.stdout.write(swagger + '\n')
  })
}

module.exports = { cli, stop, generateSwagger }

if (require.main === module) {
  cli(process.argv.slice(2))
}

import { createResource } from 'solid-js'
import { isServer, Suspense } from 'solid-js/web'
import { useLocation } from 'solid-app-router'
import { RouteContext, jsonDataFetch } from '/dx:core.js'
import layouts from '/dx:layouts.js'

export default function DXRoute (props) {
  const ctx = props.payload.routeMap[props.path]
  const location = useLocation()

  ctx.state = props.state
  ctx.actions = props.payload.serverRoute.actions

  if (isServer) {
    ctx.layout = props.payload.serverRoute.layout ?? 'default'
    ctx.data = props.payload.serverRoute.data
  }

  async function setup () {
    if (props.payload.serverRoute.firstRender) {
      // ctx.hydration = payload.serverRoute.hydration
      ctx.data = props.payload.serverRoute.data
      ctx.layout = props.payload.serverRoute.layout ?? 'default'
      props.payload.serverRoute.firstRender = false
      return ctx
    }
    ctx.layout = ctx.layout ?? 'default'
    const { getMeta, getData, onEnter } = await ctx.loader()
    if (getData) {
      try {
        const fullPath = `${location.pathname}${location.search}`
        const updatedData = await jsonDataFetch(fullPath)
        if (!ctx.data) {
          ctx.data = {}
        }
        if (updatedData) {
          Object.assign(ctx.data, updatedData)
        }
        ctx.error = null
      } catch (error) {
        ctx.error = error
      }
    }
    if (getMeta) {
      const updatedMeta = await getMeta(ctx)
      if (updatedMeta) {
        props.payload.head.update(updatedMeta)
      }
    }
    if (onEnter) {
      const updatedData = await onEnter(ctx)
      if (updatedData) {
        Object.assign(ctx.data, updatedData)
      }
    }
    return ctx
  }

  let element
  if (isServer) {
    element = (
      <RouteContext.Provider value={ctx}>
        <Layout id={ctx.layout}>
          <props.component />
        </Layout>
      </RouteContext.Provider>
    )
  } else {
    const [routeContext] = createResource(setup)
    element = (
      <Suspense>
        {!routeContext.loading &&
          <RouteContext.Provider value={routeContext()}>
            <Layout id={routeContext().layout}>
              <props.component />
            </Layout>
          </RouteContext.Provider>
        }
      </Suspense>
    )
  }
  return element
}

function Layout (props) {
  const Component = layouts[props.id].default
  return <Component>{props.children}</Component>
}

'use strict'

const schemas = require('../schemas/todo')

module.exports = async function (fastify, opts) {
  fastify.addHook('onRequest', async (request, reply) => {
    try {
      await request.jwtVerify()
    } catch (err) {
      reply.send(err)
    }
  })

  fastify.setNotFoundHandler(function (request, reply) {
    reply
      .code(404)
      .type('application/json')
      .send({ message: 'Requested todo item does not exist' })
  })

  fastify.get(
    '/',
    { schema: schemas.findAll },
    async function (request, reply) {
      const limit = parseInt(request.query.limit) || 0
      const offset = parseInt(request.query.offset) || 0
      return this.mongo.db
        .collection('todo')
        .find()
        .sort({ timestamp: -1 })
        .skip(offset)
        .limit(limit)
        .toArray()
    }
  )

  fastify.get(
    '/:name',
    { schema: schemas.findOne },
    async function (request, reply) {
      const item = await this.mongo.db
        .collection('todo')
        .findOne({ name: request.params.name })

      if (item == null) {
        return reply.callNotFound()
      }

      return item
    }
  )

  fastify.post(
    '/',
    { schema: schemas.insertOne },
    async function (request, reply) {
      return this.mongo.db.collection('todo').insertOne(
        Object.assign(request.body, {
          timestamp: this.timestamp(),
          done: false
        })
      )
    }
  )

  fastify.put(
    '/:name',
    { schema: schemas.updateOne },
    async function (request, reply) {
      return this.mongo.db
        .collection('todo')
        .findOneAndUpdate(
          { name: request.params.name },
          { $set: { done: request.body.done } }
        )
    }
  )

  fastify.delete(
    '/:name',
    { schema: schemas.deleteOne },
    async function (request, reply) {
      return this.mongo.db
        .collection('todo')
        .deleteOne({ name: request.params.name })
    }
  )
}

