import { join } from 'node:path';
import AutoLoad, { AutoloadPluginOptions } from '@fastify/autoload';
import {
  FastifyError,
  FastifyPluginAsync,
  FastifyReply,
  FastifyRequest,
  FastifyServerOptions
} from 'fastify';

export interface AppOptions
  extends FastifyServerOptions,
    Partial<AutoloadPluginOptions> {}

// Centralized configuration
export const options: AppOptions = {
  bodyLimit: 1048576 * 50,
  logger: {
    level: process.env.LOG_LEVEL || 'info',
    formatters: {
      level: (label) => {
        return { level: label.toUpperCase() };
      }
    },
    transport:
      process.env.LOG_LEVEL === 'debug'
        ? {
            target: 'pino-pretty',
            options: {
              translateTime: 'SYS:dd-mm-yyyy HH:MM:ss',
              ignore: 'pid,hostname',
              colorize: true
            }
          }
        : undefined
  },
  ajv: {
    customOptions: {
      removeAdditional: 'all'
    }
  }
};

const app: FastifyPluginAsync<AppOptions> = async (
  fastify,
  opts
): Promise<void> => {

  // Centralized error handling
  fastify.setErrorHandler((error: FastifyError, request: FastifyRequest, reply: FastifyReply) => {
    const statusCode = error.statusCode ?? 500;
    request.log.error({ err: error });

    const response = {
      statusCode,
      error:
        error.code ??
        (statusCode >= 500 ? 'Internal Server Error' : 'Bad Request'),
      message:
        statusCode >= 500 && process.env.NODE_ENV === 'production'
          ? 'Internal Server Error'
          : error.message,
      ...(error.validation ? { details: error.validation } : {})
    };

    return reply.status(statusCode).send(response);
  });

  await fastify.register(AutoLoad, {
    dir: join(__dirname, 'plugins'),
    options: opts
  });

  await fastify.register(AutoLoad, {
    dir: join(__dirname, 'modules'),
    options: { ...opts, prefix: '/api' },
    encapsulate: true,
    maxDepth: 2,
    indexPattern: /.*plugin\.ts$/,
    ignorePattern: /.*\.(schema|service|routes)\.ts$/
  });

};

export default app;
export { app };

import { FastifyPluginAsyncTypebox } from "@fastify/type-provider-typebox";
import {
  createUserSchema,
  getAllUsersSchema,
  getUserSchema,
  updateUserSchema,
  deleteUserSchema,
  CreateUserDto,
  UpdateUserDto,
  UserParams
} from "./users.schema";
import { FastifyInstance } from "fastify";

const usersRoutes: FastifyPluginAsyncTypebox = async (fastify: FastifyInstance) => {

  fastify.post<{ Body: CreateUserDto }>(
    "/",
    {
      preHandler: [fastify.checkToken],
      schema: createUserSchema
    },
    async (request, reply) => {
      try {
        const user = await fastify.usersService.createUser(request.body);
        return reply.code(201).send(user);
      } catch (err) {
        fastify.log.error(err);
        return reply.code(400).send({ error: "Error creating user" });
      }
    }
  );

  // GET ALL
  fastify.get(
    "/",
    {
      preHandler: [fastify.checkToken],
      schema: getAllUsersSchema
    },
    async (_, reply) => {
      const users = await fastify.usersService.getUsers();
      return reply.send(users);
    }
  );

  fastify.get<{ Params: UserParams }>(
    "/:id",
    {
      preHandler: [fastify.checkToken],
      schema: getUserSchema
    },
    async (request, reply) => {
      const user = await fastify.usersService.getUserById(request.params.id);
      if (!user) {
        return reply.code(404).send({ error: "User not found" });
      }
      return reply.send(user);
    }
  );

  fastify.put<{ Params: UserParams; Body: UpdateUserDto }>(
    "/:id",
    {
      preHandler: [fastify.checkToken],
      schema: updateUserSchema
    },
    async (request, reply) => {
      try {
        const user = await fastify.usersService.updateUser(
          request.params.id,
          request.body
        );
        return reply.send(user);
      } catch (err) {
        fastify.log.error(err);
        return reply.code(400).send({ error: "Error updating user" });
      }
    }
  );

  fastify.delete<{ Params: UserParams }>(
    "/:id",
    {
      preHandler: [fastify.checkToken],
      schema: deleteUserSchema
    },
    async (request, reply) => {
      await fastify.usersService.deleteUser(request.params.id);
      return reply.status(204).send();
    }
  );
};

export default usersRoutes;
